358	/* =====================================================================
359	   Item Detail — Direction A "Two-column dossier" redesign
360	   Design tokens + design-system classes (ported from the handoff spec).
361	   All scoped under .df-redesign so the rest of the app is untouched.
362	   ===================================================================== */
363	
364	.df-redesign {
365	  /* fonts */
366	  --sans: 'Hanken Grotesk', system-ui, -apple-system, sans-serif;
367	  --mono: 'IBM Plex Mono', ui-monospace, 'SFMono-Regular', monospace;
368	
369	  /* ink / text */
370	  --ink: #1c1b22;
371	  --ink-2: #46454f;
372	  --ink-3: #76747f;
373	  --ink-4: #a8a6af;
374	
375	  /* lines & surfaces */
376	  --line: #e7e3dd;
377	  --line-2: #f0ece6;
378	  --paper: #ffffff;
379	  --bg: #f5f3ef;
380	  --chip: #f1eee9;
381	
382	  /* brand (deep indigo) */
383	  --brand: #3f3d86;
384	  --brand-700: #302e63;
385	  --brand-50: #ecebf6;
386	
387	  /* accent (warm clay) */
388	  --accent: #c2662f;
389	  --accent-700: #9a4f23;
390	  --accent-50: #f7ece2;
391	
392	  font-family: var(--sans);
393	  color: var(--ink);
394	  background: var(--bg);
395	  -webkit-font-smoothing: antialiased;
396	  padding: 16px 26px 26px;
397	  min-height: 100%;
398	  box-sizing: border-box;
399	
400	  *,
401	  *::before,
402	  *::after {
403	    box-sizing: border-box;
404	  }
405	
406	  .df-mono {
407	    font-family: var(--mono);
408	    font-feature-settings: "tnum" 1;
409	  }
410	}
411	
412	/* ---- hue palette (badge / field bar / labels / chips / tabs) ---- */
413	$df-tones: (
414	  "indigo": (#eceaf7, #403d8c),
415	  "violet": (#f1e7f8, #7d3ca3),
416	  "teal":   (#dff0ed, #1d7a6d),
417	  "green":  (#e6f1e9, #2e7a4d),
418	  "amber":  (#f8eed9, #9a6810),
419	  "clay":   (#f8eadf, #9c4f22),
420	  "blue":   (#e4edfc, #285aac),
421	  "rose":   (#fae6ec, #aa3957),
422	);
423	
424	/* icon badge */
425	.df-redesign .df-badge {
426	  display: inline-flex;
427	  align-items: center;
428	  justify-content: center;
429	  width: 28px;
430	  height: 28px;
431	  border-radius: 7px;
432	  flex: none;
433	
434	  .mat-icon,
435	  mat-icon {
436	    width: 16px;
437	    height: 16px;
438	    font-size: 16px;
439	    line-height: 16px;
440	  }
441	
442	  &.df-badge--sm {
443	    width: 22px;
444	    height: 22px;
445	    .mat-icon,
446	    mat-icon { width: 13px; height: 13px; font-size: 13px; line-height: 13px; }
447	  }
448	  &.df-badge--lg {
449	    width: 30px;
450	    height: 30px;
451	  }
452	}
453	
454	@each $name, $pair in $df-tones {
455	  $bg: list.nth($pair, 1);
456	  $fg: list.nth($pair, 2);
457	
458	  .df-redesign .df-badge--#{$name} {
459	    background: $bg;
460	    color: $fg;
461	  }
462	
463	  /* colored field (4-col attribute grid) */
464	  .df-redesign .df-field--#{$name} {
465	    border-left: 2.5px solid $fg;
466	    .df-field-label { color: $fg; }
467	    .df-mg { background: $bg; color: $fg; }
468	  }
469	
470	  /* standalone kicker tint */
471	  .df-redesign .df-kicker--#{$name} { color: $fg; }
472	
473	  /* primary tab tone */
474	  .df-redesign .df-tab--#{$name}.is-active {
475	    background: $bg;
476	    color: $fg;
477	    border-bottom-color: $fg;
478	    .df-badge { box-shadow: 0 0 0 1.5px rgba($fg, 0.2); }
479	  }
480	  .df-redesign .df-tab--#{$name} .df-kicker { color: $fg; }
481	}
482	
483	/* ---- status pills ---- */
484	.df-redesign .df-pill {
485	  display: inline-flex;
486	  align-items: center;
487	  gap: 6px;
488	  height: 22px;
489	  padding: 0 9px;
490	  border-radius: 999px;
491	  background: var(--chip);
492	  color: var(--ink-2);
493	  font-size: 11.5px;
494	  font-weight: 600;
495	  letter-spacing: 0.01em;
496	  white-space: nowrap;
497	
498	  .df-dot {
499	    width: 6px;
500	    height: 6px;
501	    border-radius: 99px;
502	    background: var(--ink-3);
503	    flex: none;
504	  }
505	
506	  &.df-pill--brand   { background: var(--brand-50); color: var(--brand-700); .df-dot { background: var(--brand); } }
507	  &.df-pill--success { background: #e8f1ea; color: #2f6a45; .df-dot { background: #3f8a5b; } }
508	  &.df-pill--warning { background: #f7efe0; color: #8a6312; .df-dot { background: #c08a2a; } }
509	  &.df-pill--danger  { background: #f7e7e4; color: #9a3a30; .df-dot { background: #bd5246; } }
510	  &.df-pill--accent  { background: var(--accent-50); color: var(--accent-700); .df-dot { background: var(--accent); } }
511	}
512	
513	/* ---- page header (single horizontal line) ---- */
514	.df-redesign .df-header {
515	  display: flex;
516	  align-items: center;
517	  justify-content: space-between;
518	  gap: 16px;
519	  background: var(--paper);
520	  border: 1px solid var(--line);
521	  border-radius: 12px;
522	  box-shadow: 0 1px 2px rgba(28, 27, 34, 0.04);
523	  padding: 10px 18px;
524	  margin-bottom: 12px;
525	
526	  .df-header-main {
527	    min-width: 0;
528	    display: flex;
529	    flex-direction: row;
530	    flex-wrap: wrap;
531	    align-items: center;
532	    gap: 7px 14px;
533	  }
534	  .df-header-status { display: inline-flex; align-items: center; gap: 8px; flex-wrap: wrap; }
535	
536	  h1 {
537	    margin: 0;
538	    font-size: 19px;
539	    font-weight: 700;
540	    letter-spacing: -0.02em;
541	    line-height: 1.15;
542	    color: var(--ink);
543	    white-space: nowrap;
544	  }
545	
546	  .df-identity {
547	    display: flex;
548	    align-items: center;
549	    flex-wrap: wrap;
550	    gap: 6px 16px;
551	  }
552	  .df-id-pair {
553	    display: inline-flex;
554	    align-items: baseline;
555	    gap: 6px;
556	  }
557	  .df-id-key {
558	    font-size: 10.5px;
559	    font-weight: 600;
560	    letter-spacing: 0.06em;
561	    text-transform: uppercase;
562	    color: var(--ink-3);
563	  }
564	  .df-id-val {
565	    font-family: var(--mono);
566	    font-feature-settings: "tnum" 1;
567	    font-size: 13px;
568	    font-weight: 600;
569	    color: var(--ink);
570	    a { color: var(--brand); text-decoration: none; }
571	  }
572	
573	  .df-header-actions { display: flex; gap: 9px; flex: none; flex-wrap: wrap; justify-content: flex-end; }
574	}
575	
576	/* ---- buttons ---- */
577	.df-redesign .df-btn {
578	  display: inline-flex;
579	  align-items: center;
580	  gap: 7px;
581	  height: 34px;
582	  padding: 0 14px;
583	  border-radius: 8px;
584	  font-family: var(--sans);
585	  font-size: 12.5px;
586	  font-weight: 600;
587	  white-space: nowrap;
588	  cursor: pointer;
589	  border: 1px solid transparent;
590	  transition: background 0.15s, border-color 0.15s, color 0.15s, box-shadow 0.15s;
591	
592	  .mat-icon, mat-icon { width: 15px; height: 15px; font-size: 15px; line-height: 15px; }
593	
594	  &.df-btn--sm { height: 28px; padding: 0 11px; font-size: 12px; }
595	  &.df-btn--primary { background: var(--brand); color: #fff; border-color: var(--brand); &:hover { background: var(--brand-700); border-color: var(--brand-700); } }
596	  &.df-btn--accent  { background: var(--accent); color: #fff; border-color: var(--accent); &:hover { background: var(--accent-700); border-color: var(--accent-700); } }
597	  &.df-btn--outline { background: var(--paper); color: var(--ink); border-color: var(--line); &:hover { background: var(--chip); } }
598	  &.df-btn--ghost   { background: transparent; color: var(--ink-2); &:hover { background: var(--chip); } }
599	  &:disabled { opacity: 0.55; cursor: default; }
600	}
601	
602	/* ---- primary tab bar (Main / Licensing / Calendar) ---- */
603	.df-redesign .df-tabbar {
604	  display: flex;
605	  gap: 6px;
606	  border-bottom: 1px solid var(--line);
607	  background: var(--paper);
608	  border-radius: 12px 12px 0 0;
609	  padding: 4px 10px 0;
610	  margin-bottom: 16px;
611	}
612	.df-redesign .df-tab {
613	  display: inline-flex;
614	  align-items: center;
615	  gap: 9px;
616	  padding: 8px 14px 9px;
617	  font-size: 13px;
618	  font-weight: 500;
619	  color: var(--ink-3);
620	  background: transparent;
621	  border: none;
622	  border-bottom: 2px solid transparent;
623	  border-radius: 8px 8px 0 0;
624	  margin-bottom: -1px;
625	  cursor: pointer;
626	  font-family: var(--sans);
627	
628	  .df-badge { opacity: 0.85; }
629	  &.is-active { font-weight: 700; .df-badge { opacity: 1; } }
630	}
631	
632	/* ---- cards ---- */
633	.df-redesign .df-card {
634	  background: var(--paper);
635	  border: 1px solid var(--line);
636	  border-radius: 12px;
637	  box-shadow: 0 1px 2px rgba(28, 27, 34, 0.04);
638	  display: flex;
639	  flex-direction: column;
640	  min-width: 0;
641	
642	  .df-card-head {
643	    display: flex;
644	    align-items: center;
645	    justify-content: space-between;
646	    gap: 12px;
647	    padding: 11px 16px;
648	    border-bottom: 1px solid var(--line-2);
649	  }
650	  .df-card-head-l { display: flex; align-items: center; gap: 10px; min-width: 0; }
651	  .df-kicker {
652	    font-size: 10px;
653	    font-weight: 700;
654	    letter-spacing: 0.09em;
655	    text-transform: uppercase;
656	  }
657	  .df-card-title {
658	    margin: 0;
659	    font-size: 13.5px;
660	    font-weight: 600;
661	    color: var(--ink);
662	    letter-spacing: -0.01em;
663	    white-space: nowrap;
664	  }
665	  .df-card-body { padding: 16px; }
666	  .df-card-body--tight { padding: 14px; }
667	}
668	
669	/* ---- production timeline band ---- */
670	.df-redesign .df-band {
671	  display: flex;
672	  align-items: center;
673	  gap: 24px;
674	  background: var(--paper);
675	  border: 1px solid var(--line);
676	  border-radius: 12px;
677	  box-shadow: 0 1px 2px rgba(28, 27, 34, 0.04);
678	  padding: 8px 22px;
679	  margin-bottom: 12px;
680	  flex-wrap: wrap;
681	
682	  .df-band-id { flex: none; display: flex; align-items: center; gap: 10px; }
683	  .df-band-id .df-kicker { font-size: 9.5px; }
684	  .df-band-id .df-band-title { font-size: 13px; font-weight: 600; line-height: 1.1; }
685	  .df-band-mid { flex: 1; min-width: 220px; padding: 0 10px; }
686	  .df-band-sep { width: 1px; height: 30px; background: var(--line-2); flex: none; }
687	  .df-band-facts { flex: 1; display: flex; flex-wrap: wrap; gap: 22px; min-width: 0; }
688	  .df-fact { display: flex; flex-direction: column; gap: 2px; }
689	  .df-fact-k { font-size: 9.5px; font-weight: 600; letter-spacing: 0.06em; text-transform: uppercase; color: var(--ink-3); }
690	  .df-fact-v { font-size: 13px; font-weight: 600; color: var(--ink); }
691	}
692	
693	/* ---- horizontal milestone timeline ---- */
694	.df-redesign .df-timeline {
695	  display: flex;
696	  align-items: flex-start;
697	  width: 100%;
698	
699	  .df-step {
700	    flex: 1;
701	    display: flex;
702	    flex-direction: column;
703	    align-items: center;
704	    position: relative;
705	    min-width: 0;
706	  }
707	  .df-step-conn {
708	    position: absolute;
709	    top: 7px;
710	    left: 50%;
711	    width: 100%;
712	    height: 2px;
713	    background: var(--line);
714	  }
715	  .df-step.is-done .df-step-conn { background: var(--brand); }
716	  .df-step-node {
717	    width: 16px;
718	    height: 16px;
719	    border-radius: 99px;
720	    z-index: 1;
721	    position: relative;
722	    background: var(--paper);
723	    border: 2px solid var(--line);
724	    display: flex;
725	    align-items: center;
726	    justify-content: center;
727	    .mat-icon, mat-icon { width: 9px; height: 9px; font-size: 9px; line-height: 9px; color: #fff; }
728	  }
729	  .df-step.is-done .df-step-node { background: var(--brand); border-color: var(--brand); }
730	  .df-step.is-current .df-step-node { border-color: var(--accent); box-shadow: 0 0 0 4px var(--accent-50); }
731	  .df-step.is-current .df-step-node::after {
732	    content: "";
733	    width: 6px; height: 6px; border-radius: 99px; background: var(--accent);
734	  }
735	  .df-step-label {
736	    margin-top: 9px;
737	    font-size: 11px;
738	    font-weight: 600;
739	    text-align: center;
740	    line-height: 1.25;
741	    white-space: nowrap;
742	    color: var(--ink-4);
743	  }
744	  .df-step.is-done .df-step-label { color: var(--ink); }
745	  .df-step.is-current .df-step-label { color: var(--accent-700); }
746	  .df-step-date { margin-top: 2px; font-size: 10.5px; color: var(--ink-3); font-family: var(--mono); }
747	}
748	
749	/* ---- main grid: compact image (left) + item attributes (right) ---- */
750	.df-redesign .df-grid-main {
751	  display: grid;
752	  /* left = ~40% of the page (image + carousel), right = ~60% (attributes) */
753	  grid-template-columns: minmax(0, 2fr) minmax(0, 3fr);
754	  gap: 14px;
755	  align-items: start;
756	  margin-bottom: 14px;
757	}
758	.df-redesign .df-main-left { display: flex; flex-direction: column; gap: 14px; min-width: 0; }
759	.df-redesign .df-main-right { min-width: 0; display: flex; flex-direction: column; gap: 14px; }
760	
761	/* Product Team + Comments side-by-side under the Attributes card */
762	.df-redesign .df-right-pair {
763	  display: grid;
764	  grid-template-columns: 1fr 1fr;
765	  gap: 14px;
766	  align-items: start;
767	}
768	@media (max-width: 900px) {
769	  .df-redesign .df-right-pair { grid-template-columns: 1fr; }
770	}
771	
772	/* Product Team members in two columns so the card doesn't waste horizontal space */
773	.df-redesign .df-team-grid {
774	  display: grid;
775	  grid-template-columns: repeat(2, minmax(0, 1fr));
776	  column-gap: 18px;
777	}
778	.df-redesign .df-team-grid .df-team-row { border-bottom: none; }
779	
780	/* legacy two-up (kept for safety) */
781	.df-redesign .df-grid-glance {
782	  display: grid;
783	  grid-template-columns: 1fr 340px;
784	  gap: 16px;
785	  align-items: start;
786	  margin-bottom: 16px;
787	}
788	.df-redesign .df-glance-row {
789	  display: flex;
790	  align-items: center;
791	  justify-content: space-between;
792	  gap: 12px;
793	  .df-glance-k { font-size: 12px; color: var(--ink-3); }
794	}
795	.df-redesign .df-divider { height: 1px; background: var(--line-2); margin: 11px 0; }
796	
797	/* ---- field grid + colored fields ---- */
798	/* auto-fill packs as many readable columns as fit → no big empty gaps */
799	.df-redesign .df-fieldgrid {
800	  display: grid;
801	  gap: 15px 18px;
802	  grid-template-columns: repeat(auto-fill, minmax(185px, 1fr));
803	}
804	.df-redesign .df-fieldgrid--2 { grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 13px; }
805	.df-redesign .df-field {
806	  display: flex;
807	  flex-direction: column;
808	  gap: 3px;
809	  min-width: 0;
810	  padding-left: 11px;
811	  border-left: 2.5px solid var(--line);
812	
813	  .df-field-label {
814	    font-size: 11px;
815	    font-weight: 600;
816	    letter-spacing: 0.06em;
817	    text-transform: uppercase;
818	    color: var(--ink-3);
819	    display: inline-flex;
820	    align-items: center;
821	    gap: 6px;
822	  }
823	  .df-mg {
824	    font-family: var(--mono);
825	    font-size: 9px;
826	    font-weight: 600;
827	    padding: 1px 5px;
828	    border-radius: 4px;
829	    letter-spacing: 0;
830	    background: var(--chip);
831	    color: var(--ink-3);
832	  }
833	  .df-field-val {
834	    font-size: 14px;
835	    font-weight: 500;
836	    line-height: 1.35;
837	    color: var(--ink);
838	    word-break: break-word;
839	  }
840	  &.is-empty .df-field-val { color: var(--ink-4); }
841	  &.df-field--plain { border-left: none; padding-left: 0; }
842	  &.df-field--wide { grid-column: 1 / -1; }
843	  .df-field-val.df-mono { font-family: var(--mono); font-feature-settings: "tnum" 1; }
844	}
845	.df-redesign .df-glance { display: flex; flex-direction: column; gap: 11px; }
846	
847	/* ---- segmented control ---- */
848	.df-redesign .df-segmented {
849	  display: inline-flex;
850	  background: var(--chip);
851	  border-radius: 9px;
852	  padding: 3px;
853	  gap: 2px;
854	  border: 1px solid var(--line-2);
855	
856	  button {
857	    height: 28px;
858	    padding: 0 16px;
859	    border-radius: 6px;
860	    border: none;
861	    cursor: pointer;
862	    font-family: var(--sans);
863	    font-size: 12.5px;
864	    font-weight: 600;
865	    background: transparent;
866	    color: var(--ink-3);
867	    &.is-active { background: var(--paper); color: var(--ink); box-shadow: 0 1px 2px rgba(28, 27, 34, 0.12); }
868	  }
869	}
870	.df-redesign .df-attr-meta { font-size: 11.5px; color: var(--ink-3); }
871	
872	/* ---- bottom row ---- */
873	.df-redesign .df-grid-bottom {
874	  display: grid;
875	  grid-template-columns: 1fr 1fr 1fr;
876	  gap: 14px;
877	  align-items: start;
878	  margin-top: 0;
879	}
880	.df-redesign .df-grid-bottom--single { grid-template-columns: 1fr; }
881	/* Tech Pack (narrow) + Tags (fills the rest) */
882	.df-redesign .df-grid-bottom--pair { grid-template-columns: minmax(0, 360px) minmax(0, 1fr); }
883	@media (max-width: 900px) {
884	  .df-redesign .df-grid-bottom--pair { grid-template-columns: 1fr; }
885	}
886	
887	/* ---- Tech Pack drag-and-drop card ---- */
888	.df-redesign .df-dropcard { transition: box-shadow 0.15s, border-color 0.15s; }
889	.df-redesign .df-dropzone {
890	  display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 5px;
891	  text-align: center; padding: 18px 16px; margin-bottom: 12px; cursor: pointer;
892	  border: 1.5px dashed var(--line); border-radius: 10px; background: var(--line-2);
893	  transition: border-color 0.15s, background 0.15s, transform 0.1s;
894	}
895	.df-redesign .df-dropzone:hover { border-color: #b9b3d6; background: #f3f1fa; }
896	.df-redesign .df-dropzone-icon {
897	  display: inline-flex; align-items: center; justify-content: center;
898	  width: 38px; height: 38px; border-radius: 99px; background: #ece9f7; color: #5b56a8;
899	}
900	.df-redesign .df-dropzone-title { font-size: 13px; font-weight: 700; color: var(--ink); }
901	.df-redesign .df-dropzone-sub { font-size: 11px; color: var(--ink-3); }
902	.df-redesign .df-dropzone-link { color: var(--brand); font-weight: 600; }
903	.df-redesign .df-dropcard.is-dragover { border-color: var(--brand); box-shadow: 0 0 0 3px rgba(63, 61, 134, 0.12); }
904	.df-redesign .df-dropcard.is-dragover .df-dropzone { border-color: var(--brand); background: #ece9f7; transform: scale(1.01); }
905	.df-redesign .df-dropcard.is-dragover .df-dropzone-icon { background: var(--brand); color: #fff; }
906	
907	/* inline uploaded-file list */
908	.df-redesign .df-filelist { display: flex; flex-direction: column; }
909	.df-redesign .df-filerow--link { text-decoration: none; color: inherit; }
910	.df-redesign .df-filerow--link .df-file-name { flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
911	.df-redesign .df-filerow--link:hover { background: var(--line-2); }
912	.df-redesign .df-filerow--link:hover .df-file-name { color: var(--brand); }
913	.df-redesign .df-file-go { font-size: 15px; width: 15px; height: 15px; color: var(--ink-4); flex: none; }
914	.df-redesign .df-stack { display: flex; flex-direction: column; gap: 16px; }
915	.df-redesign .df-link {
916	  font-size: 11.5px;
917	  color: var(--brand);
918	  font-weight: 600;
919	  cursor: pointer;
920	  background: none;
921	  border: none;
922	  font-family: var(--sans);
923	  &:hover { text-decoration: underline; }
924	}
925	
926	/* ---- avatars ---- */
927	.df-redesign .df-avatar {
928	  width: 30px;
929	  height: 30px;
930	  border-radius: 99px;
931	  flex: none;
932	  color: #fff;
933	  display: inline-flex;
934	  align-items: center;
935	  justify-content: center;
936	  font-size: 11px;
937	  font-weight: 700;
938	  letter-spacing: 0.02em;
939	  &.df-avatar--0 { background: #3b3a7c; }
940	  &.df-avatar--1 { background: #9a5b2e; }
941	  &.df-avatar--2 { background: #2f6a52; }
942	  &.df-avatar--3 { background: #7a3a6a; }
943	  &.df-avatar--4 { background: #2e5c8a; }
944	}
945	
946	/* ---- product team list ---- */
947	.df-redesign .df-team-row {
948	  display: flex;
949	  align-items: center;
950	  gap: 11px;
951	  padding: 7px 0;
952	  border-bottom: 1px solid var(--line-2);
953	  &:last-child { border-bottom: none; }
954	  .df-team-name { font-size: 12.5px; font-weight: 600; color: var(--ink); white-space: nowrap; }
955	  .df-team-role { font-size: 11px; color: var(--ink-3); white-space: nowrap; }
956	  &.is-empty .df-team-name { color: var(--ink-4); font-weight: 500; }
957	}
958	
959	/* ---- file rows ---- */
960	.df-redesign .df-file-actions { display: flex; gap: 8px; margin-bottom: 12px; }
961	.df-redesign .df-filerow {
962	  display: flex;
963	  align-items: center;
964	  gap: 11px;
965	  padding: 9px 0;
966	  border-bottom: 1px solid var(--line-2);
967	  &:last-child { border-bottom: none; }
968	  .df-file-kind {
969	    width: 30px; height: 30px; border-radius: 7px; flex: none;
970	    background: var(--chip);
971	    display: flex; align-items: center; justify-content: center;
972	    font-family: var(--mono); font-size: 9.5px; font-weight: 700;
973	  }
974	  .df-file-name { font-size: 12px; font-weight: 600; color: var(--ink); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
975	  .df-file-meta { font-size: 10.5px; color: var(--ink-3); font-family: var(--mono); }
976	}
977	
978	/* ---- tags ---- */
979	.df-redesign .df-tags { display: flex; flex-wrap: wrap; gap: 7px; }
980	.df-redesign .df-tag {
981	  display: inline-flex;
982	  align-items: center;
983	  gap: 5px;
984	  height: 24px;
985	  padding: 0 10px;
986	  border-radius: 7px;
987	  font-size: 12px;
988	  font-weight: 500;
989	  background: var(--chip);
990	  color: var(--ink-2);
991	  border: 1px solid var(--line-2);
992	  .df-hash { color: var(--ink-4); font-family: var(--mono); font-size: 10px; }
993	  &.is-first { background: var(--brand-50); color: var(--brand-700); border-color: transparent; }
994	}
995	.df-redesign .df-empty { color: var(--ink-4); font-size: 12.5px; }
996	
997	/* gallery / image card: compact the hero so it fits the narrow left column */
998	.df-redesign .df-gallery-card .df-card-body { display: flex; flex-direction: column; }
999	.df-redesign .df-gallery-card image-upload { display: block; width: 100%; }
1000	.df-redesign .df-gallery-card ::ng-deep #image-gallery,
1001	.df-redesign .df-gallery-card ::ng-deep gallery {
1002	  display: block;
1003	  width: 100%;
1004	  height: 420px;
1005	  border-radius: 10px;
1006	  overflow: hidden;
1007	}
1008	/* keep the upload/thumbnail controls under the hero from ballooning */
1009	.df-redesign .df-gallery-card ::ng-deep .bottom-strip { margin-top: 10px; }
1010	.df-redesign .df-gallery-card ::ng-deep .drag-and-drop { max-width: 60px; height: auto; }
1011	
1012	/* keep the edit-mode forms readable inside the redesigned shell */
1013	.df-redesign .df-edit-shell { background: var(--paper); border: 1px solid var(--line); border-radius: 12px; padding: 8px 4px; }
1014	
1015	/* ---- responsive collapse (authored at 1340px) ---- */
1016	@media (max-width: 1100px) {
1017	  /* stack the image above the attributes; attributes go full width */
1018	  .df-redesign .df-grid-main { grid-template-columns: 1fr; }
1019	  .df-redesign .df-main-left {
1020	    flex-direction: row;
1021	    flex-wrap: wrap;
1022	    align-items: stretch;
1023	  }
1024	  .df-redesign .df-main-left > .df-card { flex: 1 1 280px; }
1025	  .df-redesign .df-grid-glance { grid-template-columns: 1fr; }
1026	}
1027	@media (max-width: 920px) {
1028	  .df-redesign .df-grid-bottom { grid-template-columns: 1fr; }
1029	  .df-redesign .df-main-left { flex-direction: column; }
1030	}
1031	@media (max-width: 720px) {
1032	  .df-redesign { padding: 12px 14px 18px; }
1033	  .df-redesign .df-header { flex-direction: column; align-items: flex-start; }
1034	  .df-redesign .df-header h1 { white-space: normal; }
1035	}
