file.content:
@use 'sass:list';

.edit{
    section {
        display: flex;
        flex-direction: row;
        justify-content: space-between;
    }
    p{
        min-width: 35vw;
    }
}

.mat-expansion-indicator::after {
  transform: rotate(225deg) !important;
  color: black;
}

.item-detail-card{
    overflow: scroll;
}

  .label {
    font-weight: bold;
  }

  .flex-field {
    flex: 1 1 calc(50% - 16px); /* Two columns with spacing */
  }

  .full-width {
    width: 100%;
  }

.read-only-container {
    display: flex;
    justify-content: center;
    flex-direction: column;
    gap: 16px;
}

  mat-card-content {
    display: flex;
    flex-direction: column;
    gap: 16px;
    padding: 24px;
  }

  .read-only-field {
    display: flex;
    flex-direction: column;
    margin-bottom: 5px;
  }

  .read-only-label {
    font-weight: 600;
    color: #424242;
    font-size: 14px;
  }

  .read-only-value {
    font-size: 16px;
    color: #616161;
  }

  mat-divider {
    margin: 8px 0;
  }

  ::ng-deep.mat-ink-bar{
    display: none !important;
   }

.custom-tab-group {
  ::ng-deep .mat-tab-header {
    border-bottom: none;
  }
 ::ng-deep.mat-tab-label-active{
      border:2px solid rgb(var(--color-primary));
      border-bottom: none;
      background-color: white;
      }

 ::ng-deep .mat-tab-label:not(.mat-tab-label-active){
    border-bottom: 2px solid rgb(var(--color-primary));
    background-color: white;
 }

 ::ng-deep.mat-tab-body-wrapper{
      border-left: 2px solid rgb(var(--color-primary));
      border-right: 2px solid rgb(var(--color-primary));
      border-bottom: 2px solid rgb(var(--color-primary));
      }        
}

.design-only-overlay {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(15%, -275%);
  rotate: -45deg;
  background-color: rgba(0, 0, 0, 0.5);
  color: white;
  padding: 10px 20px;
  border-radius: 5px;
  font-size: 2.2em;
  font-weight: bold;
  z-index: 1;
}
.info-icon {
  color: #5C77FF;
  border-radius: 4px;
  margin-left: 4px;
  width: 16px;
  height: 16px;
  font-size: 16px;
  vertical-align: middle;
  display: inline-flex;
  align-items: center;
  justify-content: center;

  &:hover {
    opacity: 0.8;
  }
}

.mat-icon-sm {
  font-size: 16px;
  width: 20px;
  height: 20px;
}

.dropdown-div {
  display: flex;
  flex-direction: row;
  align-items: center;

  .dropdown-span {
      width: 50%;
      overflow: scroll;
      border: 1px solid darkgrey;
  }
}

.dropdown-div > span:first-child {
  width: 35%;
  min-width: 35%;
  max-width: 35%;
  overflow-x: auto;
  text-overflow: ellipsis;
  white-space: nowrap;
  border-right: 1px solid #ccc;
  box-sizing: border-box;
  display: flex;
  align-items: center;
  justify-content: center;
}

.dropdown-desc {
  width: 65%;
  min-width: 65%;
  max-width: 65%;
  overflow-x: auto;
  text-overflow: ellipsis;
  white-space: nowrap;
  box-sizing: border-box;
  display: flex;
  align-items: center;
  justify-content: space-around 
}

.dropdown-header {
  font-weight: bold;
  font-size: 1rem;
  border-bottom: 1px solid #ccc;
  padding: 0 16px;
}

.spinner-overlay {
  position: fixed;        // Stay on top of everything
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background-color: rgba(0,0,0,0.3); // Optional semi-transparent background
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 1000;          // Make sure it overlays all content
}

.image-viewer {
  display: flex;
  gap: 1rem;                  /* spacing between image and right cards */
}

.tracking-card {
  padding: 16px !important;
  margin-bottom: 16px;
}

.custom-tooltip {
  /* This targets the tooltip container (surface) */
  .mat-mdc-tooltip-panel,     /* fallback class */
  .mat-mdc-tooltip-surface {    /* the actual MDC surface class used in Angular Material */
    background-color: #3f51b5 !important;       /* dark gray background */
    color: #ffffff !important;                   /* white text */
    font-size: 13px !important;
    border-radius: 4px !important;
    padding: 8px 12px;
    box-shadow: 0px 2px 4px rgba(0, 0, 0, 0.4);
  }

}

.tracking {
  display: grid;
  grid-template-columns: repeat(3, 1fr); /* 4 columns */
  gap: 12px 20px;
  background: #f7f9fc;
  padding: 16px 20px;
  margin-bottom: 14px;
  border-radius: 12px;
  border: 1px solid #e2e6ea;
  align-items: center;
}

/* Keep each field on exactly one line */
.tracking mat-label {
  white-space: nowrap;        /* no wrapping */
  overflow: hidden;           /* hide overflow */
  text-overflow: ellipsis;    /* add ... */
  display: block;
  font-size: 14px;
}

/* Image Card */
.image-mat {
  border-radius: 16px !important;
  overflow: hidden;
  box-shadow: 0 10px 30px rgba(0,0,0,0.10),
              0 3px 8px rgba(0,0,0,0.06);
  transition: transform 0.2s ease, box-shadow 0.2s ease;
  padding: 1rem 1rem 1rem 1rem;    /* <<< Add clean top padding */
}

.image-mat:hover {
  transform: translateY(-4px);
  box-shadow: 0 14px 34px rgba(0,0,0,0.14),
              0 4px 10px rgba(0,0,0,0.08);
}

/* Ensure the overlay stays perfectly aligned */
.image-mat .design-only-overlay {
  border-bottom-left-radius: 16px;
  border-bottom-right-radius: 16px;
}

/* Design-only overlay styling fix */
.design-only-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  background: rgba(0,0,0,0.6);
  color: #fff;
  text-align: center;
  padding: 4px 0;
  font-weight: 600;
  border-bottom-left-radius: 16px;
  border-bottom-right-radius: 16px;
}

.card-container {
  display: flex;
  flex-direction: column;
  gap: 1rem;                    /* replaces all <br> spacing */
}

/* Universal mat-card styling */
.custom-card {
  border-radius: 16px;
  overflow: visible;
  box-shadow: 0 10px 30px rgba(0,0,0,0.10), 
              0 3px 8px rgba(0,0,0,0.06);
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.custom-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 14px 34px rgba(0,0,0,0.14), 
              0 4px 10px rgba(0,0,0,0.08);
}

/* Existing styles you already have */
.techpack-row {
  padding: 1rem;
}

.techpack-actions {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.techpack-label {
  font-weight: 600;
  min-width: 100px;
}

.tags-card {
  padding: 1rem;
}

.tags-row {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

.tags-label {
  font-weight: 600;
  min-width: 80px;
}

.tag-chip {
  font-size: 13px;
  padding: 4px 10px;
}

.product-assignments-card {
  padding: 1rem;
}

.product-assignments-card:hover {
  transform: none;
}

.product-assignments-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-weight: 600;
  margin-bottom: 12px;
}

.product-assignment-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
  gap: 10px 12px;
}

.product-assignment-field {
  width: 100%;
}

/* =====================================================================
   Item Detail — Direction A "Two-column dossier" redesign
   Design tokens + design-system classes (ported from the handoff spec).
   All scoped under .df-redesign so the rest of the app is untouched.
   ===================================================================== */

.df-redesign {
  /* fonts */
  --sans: 'Hanken Grotesk', system-ui, -apple-system, sans-serif;
  --mono: 'IBM Plex Mono', ui-monospace, 'SFMono-Regular', monospace;

  /* ink / text */
  --ink: #1c1b22;
  --ink-2: #46454f;
  --ink-3: #76747f;
  --ink-4: #a8a6af;

  /* lines & surfaces */
  --line: #e7e3dd;
  --line-2: #f0ece6;
  --paper: #ffffff;
  --bg: #f5f3ef;
  --chip: #f1eee9;

  /* brand (deep indigo) */
  --brand: #3f3d86;
  --brand-700: #302e63;
  --brand-50: #ecebf6;

  /* accent (warm clay) */
  --accent: #c2662f;
  --accent-700: #9a4f23;
  --accent-50: #f7ece2;

  font-family: var(--sans);
  color: var(--ink);
  background: var(--bg);
  -webkit-font-smoothing: antialiased;
  padding: 16px 26px 26px;
  min-height: 100%;
  box-sizing: border-box;

  *,
  *::before,
  *::after {
    box-sizing: border-box;
  }

  .df-mono {
    font-family: var(--mono);
    font-feature-settings: "tnum" 1;
  }
}

/* ---- hue palette (badge / field bar / labels / chips / tabs) ---- */
$df-tones: (
  "indigo": (#eceaf7, #403d8c),
  "violet": (#f1e7f8, #7d3ca3),
  "teal":   (#dff0ed, #1d7a6d),
  "green":  (#e6f1e9, #2e7a4d),
  "amber":  (#f8eed9, #9a6810),
  "clay":   (#f8eadf, #9c4f22),
  "blue":   (#e4edfc, #285aac),
  "rose":   (#fae6ec, #aa3957),
);

/* icon badge */
.df-redesign .df-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border-radius: 7px;
  flex: none;

  .mat-icon,
  mat-icon {
    width: 16px;
    height: 16px;
    font-size: 16px;
    line-height: 16px;
  }

  &.df-badge--sm {
    width: 22px;
    height: 22px;
    .mat-icon,
    mat-icon { width: 13px; height: 13px; font-size: 13px; line-height: 13px; }
  }
  &.df-badge--lg {
    width: 30px;
    height: 30px;
  }
}

@each $name, $pair in $df-tones {
  $bg: list.nth($pair, 1);
  $fg: list.nth($pair, 2);

  .df-redesign .df-badge--#{$name} {
    background: $bg;
    color: $fg;
  }

  /* colored field (4-col attribute grid) */
  .df-redesign .df-field--#{$name} {
    border-left: 2.5px solid $fg;
    .df-field-label { color: $fg; }
    .df-mg { background: $bg; color: $fg; }
  }

  /* standalone kicker tint */
  .df-redesign .df-kicker--#{$name} { color: $fg; }

  /* primary tab tone */
  .df-redesign .df-tab--#{$name}.is-active {
    background: $bg;
    color: $fg;
    border-bottom-color: $fg;
    .df-badge { box-shadow: 0 0 0 1.5px rgba($fg, 0.2); }
  }
  .df-redesign .df-tab--#{$name} .df-kicker { color: $fg; }
}

/* ---- status pills ---- */
.df-redesign .df-pill {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  height: 22px;
  padding: 0 9px;
  border-radius: 999px;
  background: var(--chip);
  color: var(--ink-2);
  font-size: 11.5px;
  font-weight: 600;
  letter-spacing: 0.01em;
  white-space: nowrap;

  .df-dot {
    width: 6px;
    height: 6px;
    border-radius: 99px;
    background: var(--ink-3);
    flex: none;
  }

  &.df-pill--brand   { background: var(--brand-50); color: var(--brand-700); .df-dot { background: var(--brand); } }
  &.df-pill--success { background: #e8f1ea; color: #2f6a45; .df-dot { background: #3f8a5b; } }
  &.df-pill--warning { background: #f7efe0; color: #8a6312; .df-dot { background: #c08a2a; } }
  &.df-pill--danger  { background: #f7e7e4; color: #9a3a30; .df-dot { background: #bd5246; } }
  &.df-pill--accent  { background: var(--accent-50); color: var(--accent-700); .df-dot { background: var(--accent); } }
}

/* ---- page header (single horizontal line) ---- */
.df-redesign .df-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  background: var(--paper);
  border: 1px solid var(--line);
  border-radius: 12px;
  box-shadow: 0 1px 2px rgba(28, 27, 34, 0.04);
  padding: 10px 18px;
  margin-bottom: 12px;

  .df-header-main {
    min-width: 0;
    display: flex;
    flex-direction: row;
    flex-wrap: wrap;
    align-items: center;
    gap: 7px 14px;
  }
  .df-header-status { display: inline-flex; align-items: center; gap: 8px; flex-wrap: wrap; }

  h1 {
    margin: 0;
    font-size: 19px;
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1.15;
    color: var(--ink);
    white-space: nowrap;
  }

  .df-identity {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 6px 16px;
  }
  .df-id-pair {
    display: inline-flex;
    align-items: baseline;
    gap: 6px;
  }
  .df-id-key {
    font-size: 10.5px;
    font-weight: 600;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    color: var(--ink-3);
  }
  .df-id-val {
    font-family: var(--mono);
    font-feature-settings: "tnum" 1;
    font-size: 13px;
    font-weight: 600;
    color: var(--ink);
    a { color: var(--brand); text-decoration: none; }
  }

  .df-header-actions { display: flex; gap: 9px; flex: none; flex-wrap: wrap; justify-content: flex-end; }
}

/* ---- buttons ---- */
.df-redesign .df-btn {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  height: 34px;
  padding: 0 14px;
  border-radius: 8px;
  font-family: var(--sans);
  font-size: 12.5px;
  font-weight: 600;
  white-space: nowrap;
  cursor: pointer;
  border: 1px solid transparent;
  transition: background 0.15s, border-color 0.15s, color 0.15s, box-shadow 0.15s;

  .mat-icon, mat-icon { width: 15px; height: 15px; font-size: 15px; line-height: 15px; }

  &.df-btn--sm { height: 28px; padding: 0 11px; font-size: 12px; }
  &.df-btn--primary { background: var(--brand); color: #fff; border-color: var(--brand); &:hover { background: var(--brand-700); border-color: var(--brand-700); } }
  &.df-btn--accent  { background: var(--accent); color: #fff; border-color: var(--accent); &:hover { background: var(--accent-700); border-color: var(--accent-700); } }
  &.df-btn--outline { background: var(--paper); color: var(--ink); border-color: var(--line); &:hover { background: var(--chip); } }
  &.df-btn--ghost   { background: transparent; color: var(--ink-2); &:hover { background: var(--chip); } }
  &:disabled { opacity: 0.55; cursor: default; }
}

/* ---- primary tab bar (Main / Licensing / Calendar) ---- */
.df-redesign .df-tabbar {
  display: flex;
  gap: 6px;
  border-bottom: 1px solid var(--line);
  background: var(--paper);
  border-radius: 12px 12px 0 0;
  padding: 4px 10px 0;
  margin-bottom: 16px;
}
.df-redesign .df-tab {
  display: inline-flex;
  align-items: center;
  gap: 9px;
  padding: 8px 14px 9px;
  font-size: 13px;
  font-weight: 500;
  color: var(--ink-3);
  background: transparent;
  border: none;
  border-bottom: 2px solid transparent;
  border-radius: 8px 8px 0 0;
  margin-bottom: -1px;
  cursor: pointer;
  font-family: var(--sans);

  .df-badge { opacity: 0.85; }
  &.is-active { font-weight: 700; .df-badge { opacity: 1; } }
}

/* ---- cards ---- */
.df-redesign .df-card {
  background: var(--paper);
  border: 1px solid var(--line);
  border-radius: 12px;
  box-shadow: 0 1px 2px rgba(28, 27, 34, 0.04);
  display: flex;
  flex-direction: column;
  min-width: 0;

  .df-card-head {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    padding: 11px 16px;
    border-bottom: 1px solid var(--line-2);
  }
  .df-card-head-l { display: flex; align-items: center; gap: 10px; min-width: 0; }
  .df-kicker {
    font-size: 10px;
    font-weight: 700;
    letter-spacing: 0.09em;
    text-transform: uppercase;
  }
  .df-card-title {
    margin: 0;
    font-size: 13.5px;
    font-weight: 600;
    color: var(--ink);
    letter-spacing: -0.01em;
    white-space: nowrap;
  }
  .df-card-body { padding: 16px; }
  .df-card-body--tight { padding: 14px; }
}

/* ---- production timeline band ---- */
.df-redesign .df-band {
  display: flex;
  align-items: center;
  gap: 24px;
  background: var(--paper);
  border: 1px solid var(--line);
  border-radius: 12px;
  box-shadow: 0 1px 2px rgba(28, 27, 34, 0.04);
  padding: 8px 22px;
  margin-bottom: 12px;
  flex-wrap: wrap;

  .df-band-id { flex: none; display: flex; align-items: center; gap: 10px; }
  .df-band-id .df-kicker { font-size: 9.5px; }
  .df-band-id .df-band-title { font-size: 13px; font-weight: 600; line-height: 1.1; }
  .df-band-mid { flex: 1; min-width: 220px; padding: 0 10px; }
  .df-band-sep { width: 1px; height: 30px; background: var(--line-2); flex: none; }
  .df-band-facts { flex: 1; display: flex; flex-wrap: wrap; gap: 22px; min-width: 0; }
  .df-fact { display: flex; flex-direction: column; gap: 2px; }
  .df-fact-k { font-size: 9.5px; font-weight: 600; letter-spacing: 0.06em; text-transform: uppercase; color: var(--ink-3); }
  .df-fact-v { font-size: 13px; font-weight: 600; color: var(--ink); }
}

/* ---- horizontal milestone timeline ---- */
.df-redesign .df-timeline {
  display: flex;
  align-items: flex-start;
  width: 100%;

  .df-step {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    min-width: 0;
  }
  .df-step-conn {
    position: absolute;
    top: 7px;
    left: 50%;
    width: 100%;
    height: 2px;
    background: var(--line);
  }
  .df-step.is-done .df-step-conn { background: var(--brand); }
  .df-step-node {
    width: 16px;
    height: 16px;
    border-radius: 99px;
    z-index: 1;
    position: relative;
    background: var(--paper);
    border: 2px solid var(--line);
    display: flex;
    align-items: center;
    justify-content: center;
    .mat-icon, mat-icon { width: 9px; height: 9px; font-size: 9px; line-height: 9px; color: #fff; }
  }
  .df-step.is-done .df-step-node { background: var(--brand); border-color: var(--brand); }
  .df-step.is-current .df-step-node { border-color: var(--accent); box-shadow: 0 0 0 4px var(--accent-50); }
  .df-step.is-current .df-step-node::after {
    content: "";
    width: 6px; height: 6px; border-radius: 99px; background: var(--accent);
  }
  .df-step-label {
    margin-top: 9px;
    font-size: 11px;
    font-weight: 600;
    text-align: center;
    line-height: 1.25;
    white-space: nowrap;
    color: var(--ink-4);
  }
  .df-step.is-done .df-step-label { color: var(--ink); }
  .df-step.is-current .df-step-label { color: var(--accent-700); }
  .df-step-date { margin-top: 2px; font-size: 10.5px; color: var(--ink-3); font-family: var(--mono); }
}

/* ---- main grid: compact image (left) + item attributes (right) ---- */
.df-redesign .df-grid-main {
  display: grid;
  /* left = ~40% of the page (image + carousel), right = ~60% (attributes) */
  grid-template-columns: minmax(0, 2fr) minmax(0, 3fr);
  gap: 14px;
  align-items: start;
  margin-bottom: 14px;
}
.df-redesign .df-main-left { display: flex; flex-direction: column; gap: 14px; min-width: 0; }
.df-redesign .df-main-right { min-width: 0; display: flex; flex-direction: column; gap: 14px; }

/* Product Team + Comments side-by-side under the Attributes card */
.df-redesign .df-right-pair {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
  align-items: start;
}
@media (max-width: 900px) {
  .df-redesign .df-right-pair { grid-template-columns: 1fr; }
}

/* Product Team members in two columns so the card doesn't waste horizontal space */
.df-redesign .df-team-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  column-gap: 18px;
}
.df-redesign .df-team-grid .df-team-row { border-bottom: none; }

/* legacy two-up (kept for safety) */
.df-redesign .df-grid-glance {
  display: grid;
  grid-template-columns: 1fr 340px;
  gap: 16px;
  align-items: start;
  margin-bottom: 16px;
}
.df-redesign .df-glance-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  .df-glance-k { font-size: 12px; color: var(--ink-3); }
}
.df-redesign .df-divider { height: 1px; background: var(--line-2); margin: 11px 0; }

/* ---- field grid + colored fields ---- */
/* auto-fill packs as many readable columns as fit → no big empty gaps */
.df-redesign .df-fieldgrid {
  display: grid;
  gap: 15px 18px;
  grid-template-columns: repeat(auto-fill, minmax(185px, 1fr));
}
.df-redesign .df-fieldgrid--2 { grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 13px; }
.df-redesign .df-field {
  display: flex;
  flex-direction: column;
  gap: 3px;
  min-width: 0;
  padding-left: 11px;
  border-left: 2.5px solid var(--line);

  .df-field-label {
    font-size: 11px;
    font-weight: 600;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    color: var(--ink-3);
    display: inline-flex;
    align-items: center;
    gap: 6px;
  }
  .df-mg {
    font-family: var(--mono);
    font-size: 9px;
    font-weight: 600;
    padding: 1px 5px;
    border-radius: 4px;
    letter-spacing: 0;
    background: var(--chip);
    color: var(--ink-3);
  }
  .df-field-val {
    font-size: 14px;
    font-weight: 500;
    line-height: 1.35;
    color: var(--ink);
    word-break: break-word;
  }
  &.is-empty .df-field-val { color: var(--ink-4); }
  &.df-field--plain { border-left: none; padding-left: 0; }
  &.df-field--wide { grid-column: 1 / -1; }
  .df-field-val.df-mono { font-family: var(--mono); font-feature-settings: "tnum" 1; }
}
.df-redesign .df-glance { display: flex; flex-direction: column; gap: 11px; }

/* ---- segmented control ---- */
.df-redesign .df-segmented {
  display: inline-flex;
  background: var(--chip);
  border-radius: 9px;
  padding: 3px;
  gap: 2px;
  border: 1px solid var(--line-2);

  button {
    height: 28px;
    padding: 0 16px;
    border-radius: 6px;
    border: none;
    cursor: pointer;
    font-family: var(--sans);
    font-size: 12.5px;
    font-weight: 600;
    background: transparent;
    color: var(--ink-3);
    &.is-active { background: var(--paper); color: var(--ink); box-shadow: 0 1px 2px rgba(28, 27, 34, 0.12); }
  }
}
.df-redesign .df-attr-meta { font-size: 11.5px; color: var(--ink-3); }

/* ---- bottom row ---- */
.df-redesign .df-grid-bottom {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 14px;
  align-items: start;
  margin-top: 0;
}
.df-redesign .df-grid-bottom--single { grid-template-columns: 1fr; }
/* Tech Pack (narrow) + Tags (fills the rest) */
.df-redesign .df-grid-bottom--pair { grid-template-columns: minmax(0, 360px) minmax(0, 1fr); }
@media (max-width: 900px) {
  .df-redesign .df-grid-bottom--pair { grid-template-columns: 1fr; }
}

/* ---- Tech Pack drag-and-drop card ---- */
.df-redesign .df-dropcard { transition: box-shadow 0.15s, border-color 0.15s; }
.df-redesign .df-dropzone {
  display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 5px;
  text-align: center; padding: 18px 16px; margin-bottom: 12px; cursor: pointer;
  border: 1.5px dashed var(--line); border-radius: 10px; background: var(--line-2);
  transition: border-color 0.15s, background 0.15s, transform 0.1s;
}
.df-redesign .df-dropzone:hover { border-color: #b9b3d6; background: #f3f1fa; }
.df-redesign .df-dropzone-icon {
  display: inline-flex; align-items: center; justify-content: center;
  width: 38px; height: 38px; border-radius: 99px; background: #ece9f7; color: #5b56a8;
}
.df-redesign .df-dropzone-title { font-size: 13px; font-weight: 700; color: var(--ink); }
.df-redesign .df-dropzone-sub { font-size: 11px; color: var(--ink-3); }
.df-redesign .df-dropzone-link { color: var(--brand); font-weight: 600; }
.df-redesign .df-dropcard.is-dragover { border-color: var(--brand); box-shadow: 0 0 0 3px rgba(63, 61, 134, 0.12); }
.df-redesign .df-dropcard.is-dragover .df-dropzone { border-color: var(--brand); background: #ece9f7; transform: scale(1.01); }
.df-redesign .df-dropcard.is-dragover .df-dropzone-icon { background: var(--brand); color: #fff; }

/* inline uploaded-file list */
.df-redesign .df-filelist { display: flex; flex-direction: column; }
.df-redesign .df-filerow--link { text-decoration: none; color: inherit; }
.df-redesign .df-filerow--link .df-file-name { flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.df-redesign .df-filerow--link:hover { background: var(--line-2); }
.df-redesign .df-filerow--link:hover .df-file-name { color: var(--brand); }
.df-redesign .df-file-go { font-size: 15px; width: 15px; height: 15px; color: var(--ink-4); flex: none; }
.df-redesign .df-stack { display: flex; flex-direction: column; gap: 16px; }
.df-redesign .df-link {
  font-size: 11.5px;
  color: var(--brand);
  font-weight: 600;
  cursor: pointer;
  background: none;
  border: none;
  font-family: var(--sans);
  &:hover { text-decoration: underline; }
}

/* ---- avatars ---- */
.df-redesign .df-avatar {
  width: 30px;
  height: 30px;
  border-radius: 99px;
  flex: none;
  color: #fff;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.02em;
  &.df-avatar--0 { background: #3b3a7c; }
  &.df-avatar--1 { background: #9a5b2e; }
  &.df-avatar--2 { background: #2f6a52; }
  &.df-avatar--3 { background: #7a3a6a; }
  &.df-avatar--4 { background: #2e5c8a; }
}

/* ---- product team list ---- */
.df-redesign .df-team-row {
  display: flex;
  align-items: center;
  gap: 11px;
  padding: 7px 0;
  border-bottom: 1px solid var(--line-2);
  &:last-child { border-bottom: none; }
  .df-team-name { font-size: 12.5px; font-weight: 600; color: var(--ink); white-space: nowrap; }
  .df-team-role { font-size: 11px; color: var(--ink-3); white-space: nowrap; }
  &.is-empty .df-team-name { color: var(--ink-4); font-weight: 500; }
}

/* ---- file rows ---- */
.df-redesign .df-file-actions { display: flex; gap: 8px; margin-bottom: 12px; }
.df-redesign .df-filerow {
  display: flex;
  align-items: center;
  gap: 11px;
  padding: 9px 0;
  border-bottom: 1px solid var(--line-2);
  &:last-child { border-bottom: none; }
  .df-file-kind {
    width: 30px; height: 30px; border-radius: 7px; flex: none;
    background: var(--chip);
    display: flex; align-items: center; justify-content: center;
    font-family: var(--mono); font-size: 9.5px; font-weight: 700;
  }
  .df-file-name { font-size: 12px; font-weight: 600; color: var(--ink); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .df-file-meta { font-size: 10.5px; color: var(--ink-3); font-family: var(--mono); }
}

/* ---- tags ---- */
.df-redesign .df-tags { display: flex; flex-wrap: wrap; gap: 7px; }
.df-redesign .df-tag {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  height: 24px;
  padding: 0 10px;
  border-radius: 7px;
  font-size: 12px;
  font-weight: 500;
  background: var(--chip);
  color: var(--ink-2);
  border: 1px solid var(--line-2);
  .df-hash { color: var(--ink-4); font-family: var(--mono); font-size: 10px; }
  &.is-first { background: var(--brand-50); color: var(--brand-700); border-color: transparent; }
}
.df-redesign .df-empty { color: var(--ink-4); font-size: 12.5px; }

/* gallery / image card: compact the hero so it fits the narrow left column */
.df-redesign .df-gallery-card .df-card-body { display: flex; flex-direction: column; }
.df-redesign .df-gallery-card image-upload { display: block; width: 100%; }
.df-redesign .df-gallery-card ::ng-deep #image-gallery,
.df-redesign .df-gallery-card ::ng-deep gallery {
  display: block;
  width: 100%;
  height: 420px;
  border-radius: 10px;
  overflow: hidden;
}
/* keep the upload/thumbnail controls under the hero from ballooning */
.df-redesign .df-gallery-card ::ng-deep .bottom-strip { margin-top: 10px; }
.df-redesign .df-gallery-card ::ng-deep .drag-and-drop { max-width: 60px; height: auto; }

/* keep the edit-mode forms readable inside the redesigned shell */
.df-redesign .df-edit-shell { background: var(--paper); border: 1px solid var(--line); border-radius: 12px; padding: 8px 4px; }

/* ---- responsive collapse (authored at 1340px) ---- */
@media (max-width: 1100px) {
  /* stack the image above the attributes; attributes go full width */
  .df-redesign .df-grid-main { grid-template-columns: 1fr; }
  .df-redesign .df-main-left {
    flex-direction: row;
    flex-wrap: wrap;
    align-items: stretch;
  }
  .df-redesign .df-main-left > .df-card { flex: 1 1 280px; }
  .df-redesign .df-grid-glance { grid-template-columns: 1fr; }
}
@media (max-width: 920px) {
  .df-redesign .df-grid-bottom { grid-template-columns: 1fr; }
  .df-redesign .df-main-left { flex-direction: column; }
}
@media (max-width: 720px) {
  .df-redesign { padding: 12px 14px 18px; }
  .df-redesign .df-header { flex-direction: column; align-items: flex-start; }
  .df-redesign .df-header h1 { white-space: normal; }
}

