     Team + Tech Pack stack on the left, Comments + Tags on the right. -->
<div class="df-right-cols">
  <div class="df-right-col">
  <!-- Product Team -->
  <div class="df-card">
    <div class="df-card-head">
      <div class="df-card-head-l">
        <span class="df-badge df-badge--blue"><mat-icon>group</mat-icon></span>
        <h3 class="df-card-title">Product Team</h3>
      </div>
      @if (loadingProductAssignmentUsers) {
        <mat-spinner diameter="18"></mat-spinner>
      } @else if (!editing) {
        <button class="df-link" (click)="editing = true">Edit</button>
      }
    </div>
    <div class="df-card-body">
      @if (!editing) {
        <div class="df-team-grid">
          @for (member of teamMembers; track member.role; let i = $index) {
            <div class="df-team-row" [class.is-empty]="!member.name">
              <span class="df-avatar"
                [class.df-avatar--0]="i % 5 === 0"
                [class.df-avatar--1]="i % 5 === 1"
                [class.df-avatar--2]="i % 5 === 2"
                [class.df-avatar--3]="i % 5 === 3"
                [class.df-avatar--4]="i % 5 === 4">{{ member.name ? member.initials : '—' }}</span>
              <div style="min-width: 0; flex: 1;">
                <div class="df-team-name">{{ member.name || 'Unassigned' }}</div>
                <div class="df-team-role">{{ member.label }}</div>
              </div>
            </div>
          }
        </div>
      } @else {
        <div class="product-assignment-grid">
          @for (assignmentRole of productAssignmentRoles; track assignmentRole.role) {
            <mat-form-field appearance="outline" class="product-assignment-field">
              <mat-label>{{ assignmentRole.label }}</mat-label>
              <mat-select
                [disabled]="loadingProductAssignmentUsers || savingProductAssignmentRole === assignmentRole.role"
                [(ngModel)]="selectedProductAssignments[assignmentRole.role]"
                [compareWith]="compareAssignmentUsers"
                (selectionChange)="onProductAssignmentChange(assignmentRole.role, $event)">
                <mat-option [value]="null">Unassigned</mat-option>
                @for (user of assignmentUsers; track user.id) {
                  <mat-option [value]="user">{{ getUserDisplayName(user) }}</mat-option>
                }
              </mat-select>
            </mat-form-field>
          }
        </div>
      }
    </div>
  </div>

  <!-- Comments -->
  <div class="df-card">
    <div class="df-card-head">
      <div class="df-card-head-l">
        <span class="df-badge df-badge--green"><mat-icon>chat_bubble_outline</mat-icon></span>
        <h3 class="df-card-title">Comments</h3>
      </div>
      <button class="df-link" (click)="viewNotesDialog()">View all</button>
    </div>
    <div class="df-card-body">
      <view-notes-dialog [itemId]="itemDetailId" (loaded)="onCommentsLoaded($event)"></view-notes-dialog>
    </div>
  </div>
</div><!-- /df-right-pair -->

<!-- Tech Pack (narrow) + Tags fill the rest of the right column -->
<div class="df-grid-bottom df-grid-bottom--pair">
<!-- Tech Pack & Files: drag-and-drop + inline file list -->
<div class="df-card df-dropcard" [class.is-dragover]="isTechpackDragover"
  (dragover)="onTechpackDragOver($event)" (dragleave)="onTechpackDragLeave($event)" (drop)="onTechpackDrop($event)">
  <div class="df-card-head">
    <div class="df-card-head-l">
      <span class="df-badge df-badge--violet"><mat-icon>attach_file</mat-icon></span>
      <h3 class="df-card-title">Tech Pack &amp; Files</h3>
    </div>
    @if (techpackUploading) {
      <mat-spinner diameter="18"></mat-spinner>
    }
  </div>
  <div class="df-card-body">
    <label class="df-dropzone">
      <input type="file" multiple hidden (change)="onTechpackFilesSelected($event)">
      <span class="df-dropzone-icon"><mat-icon>cloud_upload</mat-icon></span>
      <span class="df-dropzone-title">Drag &amp; drop to upload</span>
      <span class="df-dropzone-sub">or <span class="df-dropzone-link">browse files</span> · PDF, AI, JPG, PNG</span>
    </label>
    @if (techpackFiles.length) {
      <div class="df-filelist">
        @for (f of techpackFiles; track f.id) {
          <a class="df-filerow df-filerow--link" [href]="f.attachment_link" target="_blank"
            [attr.download]="f.item_attachment_fileName">
            <span class="df-file-kind">{{ techpackBadge(f.item_attachment_fileName) }}</span>
            <span class="df-file-name">{{ f.item_attachment_fileName }}</span>
            <mat-icon class="df-file-go">north_east</mat-icon>
          </a>
        }
      </div>
    } @else {
      <span class="df-empty">No files uploaded yet</span>
    }
  </div>
</div>

<!-- Tags -->
<div class="df-card">
  <div class="df-card-head">
    <div class="df-card-head-l">
      <span class="df-badge df-badge--teal"><mat-icon>sell</mat-icon></span>
      <h3 class="df-card-title">Tags</h3>
    </div>
  </div>
  <div class="df-card-body">
    @if (!editing) {
      @if (tags?.length) {
        <div class="df-tags">
          @for (t of tags; track t; let i = $index) {
            <span class="df-tag" [class.is-first]="i === 0"><span class="df-hash">#</span>{{ t }}</span>
          }
        </div>
      } @else {
        <span class="df-empty">No tags</span>
      }
    } @else {
      <mat-form-field appearance="fill" class="full-width">
        <mat-label>Tags (press ENTER to add)</mat-label>
        <mat-chip-grid #chipListBottom aria-label="Item tags">
          @for (tag of tags; track tag) {
            <mat-chip-row [removable]="true" (removed)="tags.splice(tags.indexOf(tag),1)" class="tag-chip">
              {{ tag }}
              <button matChipRemove aria-label="Remove tag"><mat-icon>cancel</mat-icon></button>
            </mat-chip-row>
          }
          <input placeholder="Add a tag" [matChipInputFor]="chipListBottom"
            [matChipInputSeparatorKeyCodes]="separatorKeysCodes"
            (matChipInputTokenEnd)="tags.push(($event.value||'').trim()); $event.input.value='';" />
        </mat-chip-grid>
      </mat-form-field>
    }
  </div>
</div>
</div><!-- /df-grid-bottom -->
</div><!-- /df-main-right -->

