import { Component, Input, OnInit, ViewChild } from '@angular/core';
import { ColDef, ISetFilter, ExcelExportParams, StatusPanelDef, GridOptions, DetailGridInfo, RowNode, RowHeightParams } from 'ag-grid-enterprise';
import { itemService } from 'src/app/helpers/services/main.service';
import { TrackingService } from 'src/app/helpers/services/tracking.service';
import { MatTableDataSource } from '@angular/material/table';
import { MatPaginator } from '@angular/material/paginator';

@Component({
    selector: 'prod-tracking',
    templateUrl: './prod-tracking.component.html',
    styleUrls: ['./prod-tracking.component.scss'],
    standalone: false
})

export class ProdTrackingComponent implements OnInit {
  @Input() showLatest: boolean
  @Input() disablePagination: boolean
  @Input() gridClass: string;
  @Input() itemDetailId: number
  @ViewChild(MatPaginator) paginator: MatPaginator;

  rowData: any;
  displayedColumns: string[] = ['username','event','actionDate'];
  latestEvent: any
  moduleName: string="prod_tracking"

  constructor(public itemService: itemService) { }

  async ngOnInit() {
    try {
      const auditlog: any = await this.itemService.getAuditLogByItemDetailId(this.itemDetailId, this.moduleName).toPromise();
      if(this.showLatest) {
        this.latestEvent = auditlog['data'][0] as any;
      } else {
        this.rowData = new MatTableDataSource(auditlog['data']);
        this.rowData.paginator = this.paginator;
      }
    } catch (err) {
      console.error('[ProdTrackingComponent] getAuditLogByItemDetailId failed:', err);
    }
  }
}

