2	import { ItemDetailComponent } from './itemDetail.component';
3	
4	/**
5	 * The Direction A redesign added small pure helpers/getters that only read
6	 * `this.itemData` / assignment state. They are exercised here via the prototype
7	 * with a minimal fake `this`, so no Angular DI / TestBed is required.
8	 */
9	const proto: any = ItemDetailComponent.prototype;
10	
11	function getter(name: string) {
12	  return Object.getOwnPropertyDescriptor(proto, name)!.get!;
13	}
14	
15	describe('initials()', () => {
16	  test('builds two-letter initials from first + last name', () => {
17	    expect(proto.initials.call(null, 'Maya Chen')).toBe('MC');
18	    expect(proto.initials.call(null, 'Daniel Okafor')).toBe('DO');
19	  });
20	
21	  test('handles single names and blanks', () => {
