import { describe, expect, test } from '@jest/globals';
import { ItemDetailComponent } from './itemDetail.component';

/**
 * The Direction A redesign added small pure helpers/getters that only read
 * `this.itemData` / assignment state. They are exercised here via the prototype
 * with a minimal fake `this`, so no Angular DI / TestBed is required.
 */
const proto: any = ItemDetailComponent.prototype;

function getter(name: string) {
  return Object.getOwnPropertyDescriptor(proto, name)!.get!;
}

describe('initials()', () => {
  test('builds two-letter initials from first + last name', () => {
    expect(proto.initials.call(null, 'Maya Chen')).toBe('MC');
    expect(proto.initials.call(null, 'Daniel Okafor')).toBe('DO');
  });

  test('handles single names and blanks', () => {
    expect(proto.initials.call(null, 'Cher')).toBe('C');
    expect(proto.initials.call(null, '')).toBe('?');
    expect(proto.initials.call(null, null)).toBe('?');
  });
});

describe('isSpruceNonLic', () => {
  test('is true only for division 9', () => {
    expect(getter('isSpruceNonLic').call({ itemData: [{ div_code_fk: 9 }] })).toBe(true);
    expect(getter('isSpruceNonLic').call({ itemData: [{ div_code_fk: 1 }] })).toBe(false);
    expect(getter('isSpruceNonLic').call({ itemData: [] })).toBe(false);
  });
});

describe('timelineItems', () => {
  test('returns the five production milestones in order', () => {
    const ctx = {
      itemData: [{
        created_time_date: '2024-12-03',
        udf_date02: '2025-01-22',
        udf_date03: '2025-02-10',
        due_date: '2025-02-28',
        udf_date01: '2025-03-14',
      }],
    };
    const items = getter('timelineItems').call(ctx);
    expect(items.map((i: any) => i.label)).toEqual(['Created', 'Test Report', 'Photography', 'Due', 'On Shelf']);
  });

  test('marks past dates done, the first non-past as current, and the rest todo', () => {
    const past = '2000-01-01';
    const future = '2999-01-01';
    const ctx = {
      itemData: [{
        created_time_date: past,
        udf_date02: past,
        udf_date03: future,
        due_date: future,
        udf_date01: future,
      }],
    };
    const states = getter('timelineItems').call(ctx).map((i: any) => i.state);
    expect(states).toEqual(['done', 'done', 'current', 'todo', 'todo']);
  });

  test('returns an empty list when no item is loaded', () => {
    expect(getter('timelineItems').call({ itemData: [] })).toEqual([]);
  });
});

describe('teamMembers', () => {
  test('maps each role to its assigned user with initials', () => {
    const ctx = {
      productAssignmentRoles: [
        { role: 'creative_designer', label: 'Creative Designer' },
        { role: 'salesperson', label: 'Salesperson' },
      ],
      selectedProductAssignments: {
        creative_designer: { name: 'Maya', lastname: 'Chen' },
        salesperson: null,
      },
      getUserDisplayName: proto.getUserDisplayName,
      initials: proto.initials,
    };
    const rows = getter('teamMembers').call(ctx);
    expect(rows[0]).toMatchObject({ role: 'creative_designer', label: 'Creative Designer', name: 'Maya Chen', initials: 'MC' });
    expect(rows[1]).toMatchObject({ role: 'salesperson', label: 'Salesperson', name: '', initials: '?' });
  });
});

