import { describe, expect, test } from '@jest/globals';
import { ImageUploadComponent } from './image-upload.component';

/**
 * `carouselVisible` is a pure getter that only reads `this.imageSliderObject`.
 * It decides how many thumbnails the PrimeNG carousel shows so the strip fills
 * its width instead of leaving trapped gaps (fixed 3 looked sparse on wide
 * screens). Exercised via the prototype with a minimal fake `this`, so no
 * Angular DI / TestBed is required.
 */
const proto: any = ImageUploadComponent.prototype;

function getter(name: string) {
  return Object.getOwnPropertyDescriptor(proto, name)!.get!;
}

describe('carouselVisible', () => {
  test('shows one slot when there are no images (never zero)', () => {
    expect(getter('carouselVisible').call({ imageSliderObject: [] })).toBe(1);
  });

  test('is resilient to a missing/undefined slider array', () => {
    expect(getter('carouselVisible').call({})).toBe(1);
    expect(getter('carouselVisible').call({ imageSliderObject: undefined })).toBe(1);
  });

  test('matches the image count when below the cap', () => {
    expect(getter('carouselVisible').call({ imageSliderObject: new Array(3) })).toBe(3);
    expect(getter('carouselVisible').call({ imageSliderObject: new Array(5) })).toBe(5);
  });

  test('caps at 5 so the strip never over-packs', () => {
    expect(getter('carouselVisible').call({ imageSliderObject: new Array(6) })).toBe(5);
    expect(getter('carouselVisible').call({ imageSliderObject: new Array(20) })).toBe(5);
  });
});

