import http from 'node:http';

// Map local dev port -> deployed sandbox API base path.
// Frontend default environment points at these localhost ports.
const TARGET = 'https://api.alsand.designflow.app';
const PORT_TO_BASE = {
  5000: '/api/core',
  5001: '/api/data_sync',
  5002: '/api/tracking',
  5003: '/api/item_master',
};

function corsHeaders(reqOrigin) {
  return {
    'Access-Control-Allow-Origin': reqOrigin || '*',
    'Access-Control-Allow-Credentials': 'true',
    'Access-Control-Allow-Methods': 'GET,POST,PUT,PATCH,DELETE,OPTIONS',
    'Access-Control-Allow-Headers':
      'Authorization,Content-Type,Accept,Origin,X-Requested-With',
    'Access-Control-Max-Age': '86400',
  };
}

function makeServer(port, base) {
  return http.createServer(async (req, res) => {
    const origin = req.headers.origin;
    if (req.method === 'OPTIONS') {
      res.writeHead(204, corsHeaders(origin));
      res.end();
      return;
    }

    // buffer the body
    const chunks = [];
    for await (const c of req) chunks.push(c);
    const body = chunks.length ? Buffer.concat(chunks) : undefined;

    const url = TARGET + base + req.url;
    // forward headers, drop hop-by-hop + host
    const fwd = { ...req.headers };
    delete fwd.host;
    delete fwd['content-length'];
    delete fwd.origin;

    try {
      const upstream = await fetch(url, {
        method: req.method,
        headers: fwd,
        body: ['GET', 'HEAD'].includes(req.method) ? undefined : body,
        redirect: 'manual',
      });
      const buf = Buffer.from(await upstream.arrayBuffer());
      const outHeaders = {};
      upstream.headers.forEach((v, k) => {
        if (k.toLowerCase() === 'content-encoding') return; // already decoded by fetch
        if (k.toLowerCase().startsWith('access-control-')) return; // we set our own
        outHeaders[k] = v;
      });
      Object.assign(outHeaders, corsHeaders(origin));
      res.writeHead(upstream.status, outHeaders);
      res.end(buf);
    } catch (err) {
      res.writeHead(502, { 'content-type': 'text/plain', ...corsHeaders(origin) });
      res.end('proxy error: ' + err.message);
      console.error(`[${port}] ${req.method} ${req.url} -> ${err.message}`);
    }
  });
}

for (const [portStr, base] of Object.entries(PORT_TO_BASE)) {
  const port = Number(portStr);
  makeServer(port, base).listen(port, '127.0.0.1', () =>
    console.log(`proxy :${port} -> ${TARGET}${base}`),
  );
}

