() => {
  // Try to read AG Grid rows for an item id
  const out = { gridCells: 0, firstRowText: null, ids: [] };
  const cells = document.querySelectorAll('.ag-cell');
  out.gridCells = cells.length;
  if (cells.length) out.firstRowText = Array.from(document.querySelectorAll('.ag-row')).slice(0,1).map(r=>r.textContent.slice(0,120))[0];
  // look for any element carrying an id-like data attr
  const rows = Array.from(document.querySelectorAll('.ag-row[row-id]')).slice(0,5).map(r=>r.getAttribute('row-id'));
  out.ids = rows;
  return out;
}

