() => {
  const r = el => el ? el.getBoundingClientRect() : null;
  const q = s => document.querySelector(s);
  const strip = q('.thumbnail-strip');
  const prev = q('.thumbnail-strip .p-carousel-prev');
  const next = q('.thumbnail-strip .p-carousel-next');
  const bottom = q('.bottom-strip');
  const fileUpload = q('.file-upload');
  const rightCols = q('.df-right-cols');
  const cols = document.querySelectorAll('.df-right-col');
  const doc = document.documentElement;
  return {
    horizontalOverflow: doc.scrollWidth - doc.clientWidth, // >0 means page scrolls horizontally
    viewport: { w: window.innerWidth, h: window.innerHeight },
    strip: r(strip) && { left: Math.round(r(strip).left), right: Math.round(r(strip).right), w: Math.round(r(strip).width) },
    prevArrow: r(prev) && { left: Math.round(r(prev).left), right: Math.round(r(prev).right) },
    nextArrow: r(next) && { left: Math.round(r(next).left), right: Math.round(r(next).right) },
    arrowsInsideStrip: (r(prev) && r(strip)) ? (r(prev).left >= r(strip).left - 1 && r(next).right <= r(strip).right + 1) : null,
    bottomStrip: r(bottom) && { w: Math.round(r(bottom).width), h: Math.round(r(bottom).height) },
    fileUploadWidth: r(fileUpload) && Math.round(r(fileUpload).width),
    rightColsCount: cols.length,
    colHeights: Array.from(cols).map(c => Math.round(r(c).height)),
  };
}

