() => {
  const strip = document.querySelector('.thumbnail-strip');
  const all = strip.querySelectorAll('*');
  const navlike = [];
  all.forEach(e => {
    const c = (e.className && e.className.baseVal!==undefined) ? e.className.baseVal : (e.className||'');
    if (/prev|next|nav/i.test(c) || /prev|next/i.test(e.getAttribute('aria-label')||'')) {
      navlike.push({tag: e.tagName, cls: c, aria: e.getAttribute('aria-label'), display: getComputedStyle(e).display});
    }
  });
  // also PrimeNG version
  const pkg = window.primeng;
  return { navlike, carouselOuterHTMLHead: strip.querySelector('.p-carousel')?.outerHTML.slice(0,300) };
}

