input.new_string:
/* PrimeNG 19 nav buttons (`*-button` classes). They are INLINE flex children of
   `.p-carousel-content` (align-self:center; flex-shrink:0), not absolute overlays,
   so they sit beside the viewport and can never overlap the drop box or the
   attributes card. Only render when the thumbnails overflow the visible count. */
::ng-deep .thumbnail-strip .p-carousel-prev-button,
::ng-deep .thumbnail-strip .p-carousel-next-button {
width: 30px;
height: 30px;
flex-shrink: 0;
border-radius: 50%;
background: rgba(255, 255, 255, 0.95) !important;
border: 1px solid #e7e3dd;
box-shadow: 0 2px 6px rgba(0, 0, 0, 0.18);
display: flex;
align-items: center;
justify-content: center;
color: #3f3d86;
}

::ng-deep .thumbnail-strip .p-carousel-prev-button:hover:not(:disabled),
::ng-deep .thumbnail-strip .p-carousel-next-button:hover:not(:disabled) {
background: #ffffff !important;
}

::ng-deep .thumbnail-strip .p-carousel-prev-button:disabled,
::ng-deep .thumbnail-strip .p-carousel-next-button:disabled {
opacity: 0.35;
cursor: default;
}

