() => {
  const r = el => el ? el.getBoundingClientRect() : null;
  const q = s => document.querySelector(s);
  const strip = q('.thumbnail-strip');
  const prev = q('.thumbnail-strip .p-carousel-prev-button');
  const next = q('.thumbnail-strip .p-carousel-next-button');
  const galleryCard = q('.df-gallery-card');
  const attrCard = q('.df-main-right .df-card');
  const s=r(strip),p=r(prev),n=r(next),gc=r(galleryCard),ac=r(attrCard);
  return {
    viewport: window.innerWidth,
    arrowsPresent: !!(prev&&next),
    strip: s&&{left:Math.round(s.left),right:Math.round(s.right)},
    prev: p&&{left:Math.round(p.left),right:Math.round(p.right),w:Math.round(p.width)},
    next: n&&{left:Math.round(n.left),right:Math.round(n.right),w:Math.round(n.width)},
    prevInsideStrip: (p&&s)? p.left >= s.left-1 : null,
    nextInsideStrip: (n&&s)? n.right <= s.right+1 : null,
    galleryCardRight: gc&&Math.round(gc.right),
    attrCardLeft: ac&&Math.round(ac.left),
    nextSpillsIntoAttrs: (n&&ac)? n.right > ac.left : null,
    nextSpillsOutOfCard: (n&&gc)? n.right > gc.right : null,
  };
}

