() => {
  const r = el => el ? el.getBoundingClientRect() : null;
  const q = s => document.querySelector(s);
  const strip = q('.thumbnail-strip');
  const prev = q('.thumbnail-strip .p-carousel-prev-button');
  const next = q('.thumbnail-strip .p-carousel-next-button');
  const viewport = q('.thumbnail-strip .p-carousel-viewport');
  const galleryCard = q('.df-gallery-card');
  const attrCard = q('.df-main-right .df-card');
  const thumbs = document.querySelectorAll('.thumbnail-strip .p-carousel-item .image-container img');
  const s=r(strip),p=r(prev),n=r(next),v=r(viewport),gc=r(galleryCard),ac=r(attrCard);
  // visible thumbnails = those whose center is within the strip box
  let visibleThumbs=0; thumbs.forEach(t=>{const tr=t.getBoundingClientRect(); const c=tr.left+tr.width/2; if(c>=s.left && c<=s.right) visibleThumbs++;});
  return {
    viewport_w: window.innerWidth,
    arrowsPresent: !!(prev&&next),
    strip: s&&{left:Math.round(s.left),right:Math.round(s.right)},
    prev: p&&{left:Math.round(p.left),right:Math.round(p.right)},
    next: n&&{left:Math.round(n.left),right:Math.round(n.right)},
    prevInsideStrip: (p&&s)? (p.left >= s.left-1 && p.right <= s.right+1) : null,
    nextInsideStrip: (n&&s)? (n.left >= s.left-1 && n.right <= s.right+1) : null,
    nextSpillsIntoAttrs: (n&&ac)? n.right > ac.left : null,
    nextSpillsOutOfCard: (n&&gc)? n.right > gc.right+1 : null,
    thumbsTotal: thumbs.length,
    thumbsVisibleInStrip: visibleThumbs,
  };
}

