import type { Page } from '@playwright/test';
import { expect } from '@playwright/test';
import { itemDetailUrl } from '../utils/urls';

/**
 * Page object for the redesigned Item Detail screen (`/apps/itemDetail/:item`).
 * Covers the areas reworked in the "eliminate wasted space / responsive carousel /
 * Production Tracking tab" change so regressions in any of them fail loudly.
 * Automation only — not part of the application bundle.
 */
export class ItemDetailPage {
	constructor(private readonly page: Page) {}

	async goto(itemId: number | string): Promise<void> {
		await this.page.goto(itemDetailUrl(itemId));
	}

	async expectLoaded(): Promise<void> {
		await expect(this.page).toHaveURL(/\/apps\/itemDetail\//);
		await expect(this.page.locator('.df-redesign')).toBeVisible({ timeout: 60_000 });
		await expect(this.page.getByRole('heading', { level: 1 })).toBeVisible();
	}

	/** The consolidated tab bar must always expose Main, Production Tracking and Calendar. */
	async expectTabs(): Promise<void> {
		const nav = this.page.locator('.df-tabbar');
		await expect(nav.getByRole('button', { name: /^Main/ })).toBeVisible();
		await expect(nav.getByRole('button', { name: /Production Tracking/ })).toBeVisible();
		await expect(nav.getByRole('button', { name: /Calendar/ })).toBeVisible();
	}

	async openProductionTracking(): Promise<void> {
		await this.page.locator('.df-tabbar').getByRole('button', { name: /Production Tracking/ }).click();
		// the item-scoped prod-tracking component + its audit-log table
		await expect(this.page.locator('prod-tracking')).toBeVisible({ timeout: 60_000 });
		await expect(this.page.locator('prod-tracking table, prod-tracking mat-table')).toBeVisible();
	}

	/** The right column is split into exactly two balanced sub-columns (Team+TechPack | Comments+Tags). */
	async expectRightColumnsBalanced(): Promise<void> {
		const cols = this.page.locator('.df-right-cols .df-right-col');
		await expect(cols).toHaveCount(2);
		await expect(this.page.getByRole('heading', { name: 'Product Team' })).toBeVisible();
		await expect(this.page.getByRole('heading', { name: 'Tech Pack & Files' })).toBeVisible();
		await expect(this.page.getByRole('heading', { name: 'Comments' })).toBeVisible();
		await expect(this.page.getByRole('heading', { name: 'Tags' })).toBeVisible();
	}

	/** The page must never scroll horizontally at the given viewport width. */
	async expectNoHorizontalOverflow(): Promise<void> {
		const overflow = await this.page.evaluate(
			() => document.documentElement.scrollWidth - document.documentElement.clientWidth,
		);
		expect(overflow).toBeLessThanOrEqual(1);
