import { test, expect } from '../fixtures/test.fixture';
import { ROUTES } from '../utils/urls';

const email = process.env.E2E_EMAIL;
const password = process.env.E2E_PASSWORD;

/**
 * Regression coverage for the Item Detail redesign pass:
 *  - consolidated header/tab bar exposes the always-on Production Tracking tab,
 *  - the item-scoped prod-tracking component actually loads on that tab,
 *  - the right column is split into two balanced sub-columns (no trapped gap),
 *  - the thumbnail carousel arrows stay inside the strip at multiple widths
 *    (the overlap-onto-neighbours bug), with no horizontal page overflow.
 *
 * The item id is read from the live Item Library grid so the test isn't pinned
 * to a specific sandbox record.
 */
test.describe('Item Detail redesign', () => {
	test.skip(!email || !password, 'Set E2E_EMAIL and E2E_PASSWORD to run authenticated flows.');

	let itemId: string;

	test.beforeEach(async ({ loginPage, page }) => {
		await loginPage.goto();
		await loginPage.login(email!, password!);
		await expect(page).not.toHaveURL(/\/login$/, { timeout: 60_000 });

		// grab the first item id from the library grid
		await page.goto(ROUTES.itemLibrary);
		const firstRow = page.locator('.ag-center-cols-container .ag-row[row-id]').first();
		await expect(firstRow).toBeVisible({ timeout: 60_000 });
		itemId = (await firstRow.getAttribute('row-id'))!;
		expect(itemId).toBeTruthy();
	});

	test('shows the Production Tracking tab and loads its content', async ({ itemDetailPage }) => {
		await itemDetailPage.goto(itemId);
		await itemDetailPage.expectLoaded();
		await itemDetailPage.expectTabs();
		await itemDetailPage.openProductionTracking();
	});

	test('lays the right column out as two balanced sub-columns', async ({ itemDetailPage }) => {
		await itemDetailPage.goto(itemId);
		await itemDetailPage.expectLoaded();
		await itemDetailPage.expectRightColumnsBalanced();
	});

	test('keeps the carousel arrows contained and avoids horizontal overflow across widths', async ({
		itemDetailPage,
		page,
	}) => {
		await itemDetailPage.goto(itemId);
		await itemDetailPage.expectLoaded();

		for (const width of [1440, 1300, 1024, 700]) {
			await page.setViewportSize({ width, height: 900 });
			await itemDetailPage.expectNoHorizontalOverflow();
			await itemDetailPage.expectCarouselArrowsContained();
		}
	});
});

