var DBConfig = require('../config/db.config')()
var Sequelize = require('sequelize');
var db = {};

// ~30 model files read process.env.schema (lowercase); deployed envs set SCHEMA only.
if (!process.env.schema && process.env.SCHEMA) {
    process.env.schema = process.env.SCHEMA;
}

function envInt(name, fallback) {
    const n = Number(process.env[name]);
    return Number.isFinite(n) ? n : fallback;
}

function buildDialectOptions() {
    const opts = {
        client_encoding: 'UTF8',
        connectTimeout: envInt('DB_CONNECT_TIMEOUT', 15000),
        keepAlive: true,
        keepAliveInitialDelayMillis: 10000,
    };
    if (process.env.DB_SSL === 'true') {
        opts.ssl = { require: true, rejectUnauthorized: false };
    }
    return opts;
}

function buildPoolOptions() {
    return {
        max: envInt('DB_POOL_MAX', 22),
        min: envInt('DB_POOL_MIN', 0),
        acquire: envInt('DB_POOL_ACQUIRE', 20000),
        idle: envInt('DB_POOL_IDLE', 10000),
        evict: envInt('DB_POOL_EVICT', 5000),
    };
}

initialize();
async function initialize() {
    const sequelize = new Sequelize(DBConfig.DB, DBConfig.DBUser, DBConfig.PASSWORD, {
        dialect: 'postgres',
        host: DBConfig.HOST,
        port: Number(DBConfig.PORT) || 5432,
        schema: process.env.SCHEMA,
        logging: false,
        pool: buildPoolOptions(),
        createdAt: false,
        updatedAt: false,
        timestamp: false,
        dialectOptions: buildDialectOptions(),
    });

    // Models must load before any await — require('./db') consumers read module.exports
    // immediately; reassigning `db` after await leaves them with an empty object.
    Object.assign(db, require('./db/init-models')(sequelize));
    db.sequelize = sequelize;

    try {
        await sequelize.authenticate();
        const port = Number(DBConfig.PORT) || 5432;
        const ssl = process.env.DB_SSL === 'true';
        console.log('Connection has been established successfully.');
        console.log(`🗄️  Database: ${DBConfig.DBUser}@${DBConfig.HOST}:${port}/${DBConfig.DB} (schema: ${process.env.SCHEMA}, ssl: ${ssl})`);
    } catch (error) {
        console.error('Unable to connect to the database:', error);
        throw error;
